def run(initial_state=None):
    """Execute the program with optional initial state overrides."""
    state = _InstrumentedState({**_default_state(), **(initial_state or {})})
    state.setdefault('_display', [])
    state.setdefault('_calls', [])
    state.setdefault('_execs', [])
    state.setdefault('_reads', [])
    state.setdefault('_writes', [])
    state.setdefault('_abended', False)
    state.setdefault('_branches', set())
    state.setdefault('_stub_log', [])
    dict.__setitem__(state, '_initial_snapshot', {k: v for k, v in state.items() if not k.startswith('_')})
    try:
        para_MAIN_PARA(state)
        para_PROCESS_ENTER_KEY(state)
        para_PROCESS_PF7_KEY(state)
        para_PROCESS_PF8_KEY(state)
        para_PROCESS_PAGE_FORWARD(state)
        para_PROCESS_PAGE_BACKWARD(state)
        para_POPULATE_TRAN_DATA(state)
        para_INITIALIZE_TRAN_DATA(state)
        para_RETURN_TO_PREV_SCREEN(state)
        para_SEND_TRNLST_SCREEN(state)
        para_RECEIVE_TRNLST_SCREEN(state)
        para_POPULATE_HEADER_INFO(state)
        para_STARTBR_TRANSACT_FILE(state)
        para_READNEXT_TRANSACT_FILE(state)
        para_READPREV_TRANSACT_FILE(state)
        para_ENDBR_TRANSACT_FILE(state)
    except _GobackSignal:
        pass
    except ZeroDivisionError:
        state['_abended'] = True
    _snap = dict.__getitem__(state, '_initial_snapshot')
    state['_state_diffs'] = {
        k: {'from': _snap[k], 'to': dict.__getitem__(state, k)}
        for k in _snap
        if _snap[k] != dict.get(state, k)
    }
    return state


if __name__ == '__main__':
    result = run()
    for line in result.get('_display', []):
        print(line)

